const Q_BIOLOGY_2021_MODEL_I=[{"id": "objective>Biology>2021-Model-I>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following organisms exhibits both plant and animal characteristics?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">amoeba</div>", "<div style=\"font-family:Cambria;font-size:17px;\">spirogyra</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mucor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">euglena</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Euglena exhibits both plant and animal characteristics. It is a single-celled organism that can photosynthesize like a plant and move using a whip-like structure (flagellum) like an animal. The other options, amoeba, spirogyra, and mucor, do not exhibit both plant and animal characteristics.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : PROTISTA"}, {"id": "objective>Biology>2021-Model-I>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not an organ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Hair </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tongue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rhizome</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Corm</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An organ is a group of tissues that perform a specific function or group of functions. Hair is not an organ, it is a structure made of keratin, a type of protein.</div>", "topic": "LIVING ORGANISMS : LEVEL OF ORGANIZATION"}, {"id": "objective>Biology>2021-Model-I>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One major difference between osmosis and diffusion is that diffusion</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">does not need a semi-permeable membrane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">does not take place in living tissues </div>", "<div style=\"font-family:Cambria;font-size:17px;\">takes place only in a liquid medium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">takes place only in a gaseous medium </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Osmosis is the movement of water molecules from an area of high concentration to an area of low concentration through a semi-permeable membrane. Diffusion, on the other hand, is the movement of molecules from an area of high concentration to an area of low concentration, but it does not require a semi-permeable membrane.</div>", "topic": "TRANSPORT : MEDIA AND PROCESSES OF MECHANISM FOR TRANSPORTATION"}, {"id": "objective>Biology>2021-Model-I>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is the difference between mitosis and meiosis?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Alignment of chromosomes along the equatorial plane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Replication of the chromosomes and the cell organelles </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pairing of homologous chromosomes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Formation of spindle fibres </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mitosis is a type of cell division that results in two daughter cells each having the same number and kind of chromosomes as the parent nucleus, typical of ordinary tissue growth. Meiosis is a type of cell division that reduces the number of chromosomes in the parent cell by half and produces four gamete cells. The process involves pairing of homologous chromosomes and crossing over or recombination.</div>", "topic": "HEREDITY : CHROMOSOMES"}, {"id": "objective>Biology>2021-Model-I>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following can be used for vegetative propagation?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ginger stem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Yam leaf</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Plantain roots </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sweet potato tuber </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Vegetative propagation is a form of asexual reproduction in plants. It involves multiplication from vegetative parts of the plant like stems, roots and leaves. The ginger stem can be used for vegetative propagation because it has nodes and internodes from which new plants can grow.</div>", "topic": "REPRODUCTION : ASEXUAL REPRODUCTION"}, {"id": "objective>Biology>2021-Model-I>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a method of artificial vegetative propagation?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">creeping stem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">layering </div>", "<div style=\"font-family:Cambria;font-size:17px;\">corm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rhizome </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Artificial vegetative propagation is a type of plant reproduction that is facilitated by humans. Layering is a method of artificial vegetative propagation where a stem attached to the plant is bent and covered with soil. New roots will develop from the stem and once established, the stem can be cut from the parent plant.</div>", "topic": "REPRODUCTION : ASEXUAL REPRODUCTION"}, {"id": "objective>Biology>2021-Model-I>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The diagram below is the root system of a leguminous plant. Study and use it to answer this question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The structures labelled II are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">groundnut seeds </div>", "<div style=\"font-family:Cambria;font-size:17px;\">underground rootnuts </div>", "<div style=\"font-family:Cambria;font-size:17px;\">root tubers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">root nodules</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The structure labelled II are the root nodules. Root nodules are small, round bumps that form on the roots of leguminous plants, such as beans, peas, and lentils. They are formed by a symbiotic relationship between the plant and a type of bacteria called rhizobia.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : ROOT"}, {"id": "objective>Biology>2021-Model-I>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> The diagram below is the root system of a leguminous plant. Study and use it to answer this question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The structures labelled II are associated with </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">storage of plant nutrients </div>", "<div style=\"font-family:Cambria;font-size:17px;\">organic acids </div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrogen-fixing bacteria </div>", "<div style=\"font-family:Cambria;font-size:17px;\">putrefying microbes </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The structure labelled II are associated with nitrogen-fixing bacteria. These bacteria reside in the part labelled II fixing atmospheric nitrogen to the soil.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : ROOT"}, {"id": "objective>Biology>2021-Model-I>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not a function of the blood?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">maintenance of body temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">formation of clot</div>", "<div style=\"font-family:Cambria;font-size:17px;\">distribution of bile </div>", "<div style=\"font-family:Cambria;font-size:17px;\">transportation of excretory materials</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The blood has many functions in the body including maintenance of body temperature, formation of clot to prevent excessive bleeding and transportation of excretory materials. However, the distribution of bile is not a function of the blood. Bile is produced by the liver and stored in the gallbladder. It is then released into the small intestine to aid in the digestion of fats.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>2021-Model-I>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements about the circulation of blood is not correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Deoxygenated blood flow into the heart through the Vena cavae</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Blood is pumped out of the heart through the aorta</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oxygenated blood is carried to the left auricle from the lungs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The oxygenated blood enters the lungs through the pulmonary vein </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The statement 'The oxygenated blood enters the lungs through the pulmonary vein' is incorrect. The pulmonary vein carries oxygenated blood from the lungs to the heart, not the other way around. The pulmonary artery carries deoxygenated blood from the heart to the lungs.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>2021-Model-I>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A difference between the auricle and the ventricle of the mammalian heart is that the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ventricles carry deoxygenated blood </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ventricles do not have outlets </div>", "<div style=\"font-family:Cambria;font-size:17px;\">auricles have no valves </div>", "<div style=\"font-family:Cambria;font-size:17px;\">walls of the ventricles are more muscular than that of the auricles <br/> </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The walls of the ventricles are more muscular than that of the auricles. This is because the ventricles have to pump blood out of the heart to the rest of the body, which requires more force and therefore more muscle.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>2021-Model-I>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following organisms respires through the body surface?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Man</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fish </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tridax</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Amoeba</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Amoeba respires through its body surface. It is a single-celled organism and does not have specialized respiratory organs. Instead, gases diffuse directly across its cell membrane.</div>", "topic": "RESPIRATION : RESPIRATORY ORGANS AND SURFACES"}, {"id": "objective>Biology>2021-Model-I>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The stomata of a leaf performs the same function as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">spiracles of insects </div>", "<div style=\"font-family:Cambria;font-size:17px;\">trachea of toads </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pharynx of man</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liver of man</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The stomata of a leaf perform the same function as the spiracles of insects. Both are involved in the process of gas exchange. Stomata are tiny openings or pores in plant tissue that allow for gas exchange. Spiracles are small openings on the surface of some animals, which usually lead to respiratory systems. They are used for breathing, similar to how stomata are used in plants.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTIONS IN ORGANISMS"}, {"id": "objective>Biology>2021-Model-I>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following does not happen during inspiration?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Intercostal muscles contract </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ribs move forward </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Thoracic cavity increases </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Diaphragm relaxes </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During inspiration (inhalation), the diaphragm contracts, not relaxes. This contraction moves the diaphragm down, increasing the volume of the thoracic cavity, and thus decreasing the pressure inside the chest, allowing air to flow into the lungs.</div>", "topic": "RESPIRATION : THE MECHANISM OF GASEOUS EXCHANGE IN PLANTS AND MAMMALS"}, {"id": "objective>Biology>2021-Model-I>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these is not an excretory product of plant?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tannin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Alkaloid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sweat</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sweat is not an excretory product of plants. It is a product of the sweat glands in animals, particularly humans, and is used for thermoregulation. Plants do not have sweat glands and do not produce sweat. They do, however, excrete other substances such as tannins, gums, and alkaloids.</div>", "topic": "EXCRETION : EXCRETORY PRODUCTS OF PLANTS"}, {"id": "objective>Biology>2021-Model-I>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these is not a function of the skin?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Protection against pathogens</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Regulation of body temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Synthesis of vitamin D</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Production of insulin</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The skin helps protect the body against pathogens, regulates body temperature through sweating, and synthesizes vitamin D when exposed to sunlight. However, insulin production is not a function of the skin — it is the pancreas that produces insulin to regulate blood sugar levels.</div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>2021-Model-I>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which part of the kidney does ultra-filtration take place?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Bowman's capsule </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Distal convoluted tubule </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Proximal convoluted tubule </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Collecting duct</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ultra-filtration in the kidney takes place in the Bowman's capsule. This is the initial stage of urine formation where blood is filtered under high pressure, and waste products are removed.</div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>2021-Model-I>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following organs is concerned with detoxification of harmful compounds?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">kidney</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lungs </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gall bladder</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Liver </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The liver is the organ primarily responsible for the detoxification of harmful compounds in the body. It does this by metabolizing drugs and toxins into more soluble compounds that can be easily excreted by the kidneys.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>2021-Model-I>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The hormone that promotes secondary sexual characteristics in females is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Insulin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Thyroxin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Testosterone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oestrogen <br/> </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The hormone that promotes secondary sexual characteristics in females is Oestrogen. Secondary sexual characteristics are those that distinguish the two sexes of a species, but that are not directly part of the reproductive system. In females, these characteristics include breast development, widening of the hips, and the pattern of body fat distribution. Oestrogen is the primary female sex hormone and it regulates the development and functioning of the female reproductive system, and it also promotes the development of these secondary sexual characteristics.</div>", "topic": "COORDINATION AND CONTROL : HORMONAL CONTROL"}, {"id": "objective>Biology>2021-Model-I>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Oil is sprayed over stagnant water in which mosquitoes breed in order to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">provide landing surface for the adult </div>", "<div style=\"font-family:Cambria;font-size:17px;\">prevent larva or pupa from attaching itself to the surface </div>", "<div style=\"font-family:Cambria;font-size:17px;\">prevent the water from overheating </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lubricate the larva for easy movement </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Oil is sprayed over stagnant water in which mosquitoes breed in order to prevent larva or pupa from attaching itself to the surface. This is a common method used to control the mosquito population. The oil forms a thin layer on the surface of the water, preventing the mosquito larvae and pupae from getting air, causing them to suffocate and die. This method is effective because mosquito larvae and pupae breathe air through tubes which they poke above the surface of the water.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>2021-Model-I>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following organisms lacks a reproductive organ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Chlamydomonas </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Toad </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pride of barbados</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cockroach</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Chlamydomonas is a genus of green algae that lacks a reproductive organ. It reproduces asexually through a process called binary fission, where the cell divides into two equal parts, each becoming a new organism. In contrast, Toad, Pride of Barbados (a type of flowering plant), and Cockroach all have reproductive organs and reproduce sexually.</div>", "topic": "REPRODUCTION : SEXUAL REPRODUCTION"}, {"id": "objective>Biology>2021-Model-I>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following features acts as a shock absorber to the developing embryo?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">amniotic fluid </div>", "<div style=\"font-family:Cambria;font-size:17px;\">umbilical cord </div>", "<div style=\"font-family:Cambria;font-size:17px;\">placenta</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Amnion</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The amniotic fluid acts as a shock absorber to the developing embryo. It is a clear, yellowish liquid that surrounds the unborn baby (fetus) during pregnancy. It is contained in the amniotic sac. It protects the fetus from physical shocks, provides it with fluids that it can breathe and swallow, and helps with the development of the fetus's lungs, digestive system, muscles, and bones.</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>2021-Model-I>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The collective name for the female parts of the flower is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gynoecium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">androecium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ovary</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stigma</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The collective name for the female parts of the flower is gynoecium. The gynoecium is the female part of the flower and is made up of one or more carpels. The carpel or multiple fused carpels form a hollow structure called an ovary, which produces and contains the ovules. The sticky tip of the carpel, the stigma, is the receptor of pollen. The supportive stalk, the style, becomes the pathway for pollen tubes to grow from pollen grains adhering to the stigma, to the ovules, carrying the reproductive material.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : LEAF"}, {"id": "objective>Biology>2021-Model-I>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the petals of a flowering plant are removed, which of the following processes is likely to be affected?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Transpiration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pollination</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Germination</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Photosynthesis</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If the petals of a flowering plant are removed, pollination is likely to be affected. Petals are often brightly colored or unusually shaped to attract pollinators. Without petals, pollinators may not be attracted to the flower, thus affecting the process of pollination.</div>", "topic": "REPRODUCTION : SEXUAL REPRODUCTION"}, {"id": "objective>Biology>2021-Model-I>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Use the diagram above to answer this question <br/>  <br/> The part labelled II in the diagram is the  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">plumule</div>", "<div style=\"font-family:Cambria;font-size:17px;\">endosperm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">radicle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coleorhiza </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The part labelled II is the endosperm. The endosperm is a nutrient-rich tissue that surrounds and nourishes the embryo in the seeds of many flowering plants. It is formed from the fusion of the female gametophyte's two polar nuclei with one of the pollen grain's two sperm nuclei. This triple fusion event is unique to flowering plants and is one of the defining characteristics of their seeds.</div>", "topic": "GROWTH : GERMINATION OF SEEDS AND CONDITION NECESSARY FOR GERMINATION OF SEEDS"}, {"id": "objective>Biology>2021-Model-I>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Use the diagram above to answer this question <br/> The part labelled IV in the diagram is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">plumule </div>", "<div style=\"font-family:Cambria;font-size:17px;\">endosperm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">radicle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coleoptile</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The part labelled IV is the radicle. The radicle is the embryonic root of a plant. It is the first part of the embryo to emerge from the seed during germination. The radicle grows downward into the soil, anchoring the seedling. In gymnosperms and dicotyledons (angiosperms with two seed leaves), the radicle becomes a taproot.</div>", "topic": "GROWTH : GERMINATION OF SEEDS AND CONDITION NECESSARY FOR GERMINATION OF SEEDS"}, {"id": "objective>Biology>2021-Model-I>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Use the diagram above to answer this question <br/> The function of the part labelled V in the diagram is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">manufacture of food </div>", "<div style=\"font-family:Cambria;font-size:17px;\">storage of food </div>", "<div style=\"font-family:Cambria;font-size:17px;\">secretion of digestive enzymes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">protection of the radicle </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The part labelled V is the coleorhiza which protects the radicle. The coleorhiza is a protective sheath that surrounds the radicle (embryonic root) of monocotyledonous plants (plants with one seed leaf). It develops from the embryonic root cap and is made up of a layer of cells that are tough and durable.</div>", "topic": "GROWTH : GERMINATION OF SEEDS AND CONDITION NECESSARY FOR GERMINATION OF SEEDS"}, {"id": "objective>Biology>2021-Model-I>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In testing for starch in a leaf, the function of alcohol is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">kill the cells of the leaf </div>", "<div style=\"font-family:Cambria;font-size:17px;\">soften the veins of the leaf </div>", "<div style=\"font-family:Cambria;font-size:17px;\">aid iodine to penetrate the cells </div>", "<div style=\"font-family:Cambria;font-size:17px;\">extract the chlorophyll from the leaf  <br/> </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the process of testing for starch in a leaf, the function of alcohol is to extract the chlorophyll from the leaf. Chlorophyll is the green pigment in plants that absorbs light energy for photosynthesis. The alcohol is used to remove this pigment so that the iodine solution can be seen clearly. If the leaf turns blue-black with iodine, it indicates the presence of starch.</div>", "topic": "NUTRITION : PLANT NUTRITION"}, {"id": "objective>Biology>2021-Model-I>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following processes removes CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> from the atmosphere?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">respiration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">photosynthesis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">transpiration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excretion</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Photosynthesis is the process that removes CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> from the atmosphere. During photosynthesis, plants take in carbon dioxide (CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>) from the atmosphere and water (H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O) from the soil. Using the energy from sunlight, they chemically convert the CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O into glucose (a type of sugar) and oxygen (O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>). The glucose is used by the plants for energy and growth, while the O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is released back into the atmosphere.</div>", "topic": "NUTRITION : PHOTOSYNTHESIS"}, {"id": "objective>Biology>2021-Model-I>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The role of bacteria in the nitrogen cycle includes the following except </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fixing atmospheric nitrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">converting ammonia to nitrites </div>", "<div style=\"font-family:Cambria;font-size:17px;\">converting to nitrite to nitrates </div>", "<div style=\"font-family:Cambria;font-size:17px;\">converting carbohydrates to carbon dioxide </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bacteria play several roles in the nitrogen cycle, including fixing atmospheric nitrogen, converting ammonia to nitrites, and converting nitrites to nitrates. However, they do not convert carbohydrates to carbon dioxide. This process is typically associated with respiration in animals and fermentation in yeast, not with bacteria in the nitrogen cycle.</div>", "topic": "ECOLOGY : NUTRIENT CYCLING IN NATURE"}, {"id": "objective>Biology>2021-Model-I>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The mode of nutrition which describes feeding habit in animals is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">autotrophic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">holozoic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">holophytic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">saprophytic </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The mode of nutrition that describes feeding habit in animals is 'holozoic'. Holozoic nutrition is a method of nutrition that involves the ingestion of complex organic substances. These substances could be plant or animal tissues. They are ingested and then digested in the body of the organism. The other options are incorrect as they refer to other types of nutrition. Autotrophic nutrition is a type of nutrition where organisms make their own food using light, water, carbon dioxide, or other chemicals. Holophytic nutrition is a type of nutrition in which organisms synthesize their food in the same way as green plants. Saprophytic nutrition is a process of obtaining nutrients by living on dead and decaying organic substances.</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>2021-Model-I>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following organisms has homodont dentition?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Rabbit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Man</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sheep</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lizard </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lizards have homodont dentition. Homodont dentition refers to a situation where all the teeth are of the same type and shape. This is common in reptiles and fish. The other options are incorrect as they have heterodont dentition, which means they have different types of teeth (incisors, canines, premolars, and molars) for different purposes.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2021-Model-I>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following plants is a carnivore?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Desmodium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sundew </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mushroom</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Platycerium </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sundew is a carnivorous plant. Carnivorous plants are plants that derive some or most of their nutrients from trapping and consuming animals or protozoans, typically insects and other arthropods. Sundew traps insects with sticky droplets on their leaves. The other options are incorrect as they are not carnivorous plants. Desmodium is a genus of flowering plants, Mushroom is a type of fungi, and Platycerium is a genus of ferns.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2021-Model-I>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The enzyme that acts on milk in the stomach is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Invertase </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Trypsin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Diastase </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Renin</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The enzyme that acts on milk in the stomach is Renin. Renin is an enzyme that is produced by cells in the stomach and it helps in the digestion of milk by curdling it. This process breaks down the protein in milk into smaller, more digestible pieces.</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>2021-Model-I>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many chromosomes will be present in a gamete if the somatic cell has eight (8) chromosomes?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a sexually reproducing organism, the number of chromosomes in a gamete is half the number of chromosomes in a somatic cell. This is because gametes are produced by a process called meiosis, which reduces the number of chromosomes by half. Therefore, if a somatic cell has 8 chromosomes, a gamete will have 4 chromosomes.</div>", "topic": "HEREDITY : CHROMOSOMES"}, {"id": "objective>Biology>2021-Model-I>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a plant of genotype Tt, what is the probability that a gamete will contain gene t?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1/2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3/4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/8</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3/8</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a plant of genotype Tt, the probability that a gamete will contain gene t is 1/2. This is because the plant has two alleles for the trait, T and t. When gametes are formed, each gamete gets one of the two alleles. Therefore, the probability that a gamete will get the t allele is 1/2.</div>", "topic": "HEREDITY : PROBABILITY IN GENETICS AND SEX DETERMINATION"}, {"id": "objective>Biology>2021-Model-I>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a cross involving a heterozygous red flowered plant (Rr) and a white flowered plant (rr). What is the probability that the offspring will be Rr?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3/2</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a cross between a heterozygous red flowered plant (Rr) and a white flowered plant (rr), the possible genotypes of the offspring are Rr and rr. The probability of getting Rr is 1/2. This is because the heterozygous red flowered plant (Rr) can pass on either R or r to the offspring, and the white flowered plant (rr) can only pass on r. Therefore, the combinations are Rr and rr, making the probability of Rr 1/2.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>2021-Model-I>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Termites are called social insects because </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the nests are built by the nasute soldiers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">they live together in communities </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the queen allocates duties to the workers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the king and queen do mate</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Termites are called social insects because they live together in communities. This is a characteristic of social insects, where individuals of the same species live in an organized way, often dividing labor and cooperating in tasks such as foraging and defense.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2021-Model-I>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following make up the bee caste?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Soldier and queen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Drones, soldiers and workers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Queen, workers and soldiers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Queen, drones and workers </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The bee caste is made up of the queen, drones, and workers. The queen is the only sexually mature female in the hive and is the mother of all other bees. Drones are male bees, and their primary role is to mate with the queen. Workers are female bees that do not reproduce, but perform all the other tasks necessary for the survival of the hive.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2021-Model-I>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following examples best describes camouflagic coloration in organism?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">butterfly which has a red coloration on the wing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A green snake in a green grass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A zebra with vertical stripes on the body </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Certain tree frogs with bright color pattern</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Camouflage coloration is a type of coloration or patterns which allow an organism to blend in with its environment. This helps the organism to hide from predators or prey. A green snake in green grass is a perfect example of this as the snake can easily blend in with the grass and remain undetected.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}];
